// === Edit the dialogue and durations below to test different shapes ===
// speaker: 'A' = Max, 'B' = Doc
// duration: seconds for that line — match what you'd expect ElevenLabs to produce
// (~2.5 wpm gives realistic pacing). Mix short hooks with longer lines.

const lines = [
  { speaker: 'A', text: "You ever notice the loudest person in the room usually wins?", duration: 3.4 },
  { speaker: 'B', text: "That's because your brain treats confidence as evidence of skill.", duration: 3.6 },
  { speaker: 'A', text: "Even when they're completely wrong?", duration: 2.1 },
  { speaker: 'B', text: "Especially when they're wrong. Doubt sounds like weakness.", duration: 3.8 },
  { speaker: 'A', text: "So the quiet experts just get steamrolled.", duration: 2.9 }
];

const runId = ('test_' + Date.now());

return lines.map((l, i) => ({
  json: {
    _parent: {
      // Minimal parent object — only fields the downstream FFmpeg code reads
      slot: 1,
      run_id: runId,
      // These are only used by Append Queue Row (cut out of this test), so we keep them empty
      idea_title: $('Globals').first().json.TEST_TITLE,
      idea_on_screen_caption: $('Globals').first().json.TEST_ON_SCREEN_CAPTION
    },
    run_id: runId,
    line_index: i,
    speaker: l.speaker,
    text: l.text,
    duration: l.duration
  }
}));

// Build an ffmpeg command that creates a silent MP3 of the desired duration.
// (anullsrc generates silence; aevalsrc='sin(440*2*PI*t)' would generate a tone if you prefer audible test audio.)
const fs = require('fs');
const path = require('path');

const workDir = $('Globals').first().json.WORK_DIR;
if (!fs.existsSync(workDir)) fs.mkdirSync(workDir, { recursive: true });

const lineCtx = $json;
const outPath = path.join(workDir, `${lineCtx.run_id}_line_${lineCtx.line_index}.mp3`);
const dur = Number(lineCtx.duration || 2).toFixed(3);

// Silent MP3 of the requested duration
const cmd = `ffmpeg -y -f lavfi -i anullsrc=r=44100:cl=mono -t ${dur} -c:a libmp3lame -b:a 128k "${outPath}"`;

return [{ json: { ...lineCtx, audio_path: outPath, ffmpeg_synth_cmd: cmd } }];

// Build per-line word_timings the same way the real workflow does: evenly distribute words across measured (here = requested) duration.
const lineCtx = $('Build Synth Command').item.json;
const words = (lineCtx.text || '').trim().split(/\s+/).filter(Boolean);
const perWord = words.length > 0 ? lineCtx.duration / words.length : 0;
const word_timings = words.map((w, i) => ({
  word: w,
  start: +(i * perWord).toFixed(3),
  end: +((i + 1) * perWord).toFixed(3)
}));

return [{
  json: {
    _parent: lineCtx._parent,
    line_index: lineCtx.line_index,
    speaker: lineCtx.speaker,
    text: lineCtx.text,
    duration: lineCtx.duration,
    word_timings,
    audio_path: lineCtx.audio_path,
    run_id: lineCtx.run_id
  }
}];

// === Same code as the real B1, copied verbatim so this test exercises the real assembly path ===
const fs = require('fs');
const path = require('path');

const arr = ($json.line_index || []).map((idx, i) => ({
  idx,
  speaker: $json.speaker[i],
  text: $json.text[i],
  duration: $json.duration[i],
  words: $json.word_timings[i],
  audio_path: $json.audio_path[i]
}));
arr.sort((a, b) => a.idx - b.idx);

const parent = $items('Build Fake Timings')[0].json._parent;
const runId = $items('Build Fake Timings')[0].json.run_id;
const workDir = $('Globals').first().json.WORK_DIR;
const font = $('Globals').first().json.CAPTION_FONT || 'Arial';

let offset = 0;
const spriteA = [];
const spriteB = [];
const globalWords = [];
for (const line of arr) {
  const winStart = offset;
  const winEnd = offset + line.duration;
  if (line.speaker === 'A') spriteA.push([winStart, winEnd]);
  else spriteB.push([winStart, winEnd]);
  for (const w of (line.words || [])) {
    if (w.start == null || w.end == null) continue;
    globalWords.push({ word: w.word, start: offset + w.start, end: offset + w.end });
  }
  offset += line.duration;
}
const totalDuration = offset;

function assTime(t) {
  const h = Math.floor(t / 3600);
  const m = Math.floor((t % 3600) / 60);
  const s = Math.floor(t % 60);
  const cs = Math.floor((t - Math.floor(t)) * 100);
  return `${h}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}.${String(cs).padStart(2,'0')}`;
}
const assHeader = `[Script Info]\nScriptType: v4.00+\nPlayResX: 720\nPlayResY: 1280\n\n[V4+ Styles]\nFormat: Name, Fontname, Fontsize, PrimaryColour, OutlineColour, BackColour, Bold, Outline, Shadow, Alignment, MarginL, MarginR, MarginV\nStyle: Cap,${font},64,&H00FFFFFF,&H00000000,&H00000000,1,6,0,2,40,40,260\n\n[Events]\nFormat: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text\n`;
const dialogueLines = globalWords.map(w => {
  const txt = String(w.word).replace(/[{}]/g, '');
  return `Dialogue: 0,${assTime(w.start)},${assTime(w.end)},Cap,,0,0,0,,${txt.toUpperCase()}`;
}).join('\n');
const assPath = path.join(workDir, `${runId}_captions.ass`);
fs.writeFileSync(assPath, assHeader + dialogueLines + '\n');

const listPath = path.join(workDir, `${runId}_concat.txt`);
fs.writeFileSync(listPath, arr.map(l => `file '${l.audio_path.replace(/'/g, "'\\''")}'`).join('\n'));
const mergedAudioPath = path.join(workDir, `${runId}_voice.mp3`);

return [{
  json: {
    ...parent,
    run_id: runId,
    total_audio_duration: totalDuration,
    sprite_a_windows: spriteA,
    sprite_b_windows: spriteB,
    ass_path: assPath,
    concat_list_path: listPath,
    merged_audio_path: mergedAudioPath
  }
}];

const fs = require('fs');
const path = require('path');
const prev = $('Build Timing + Captions').item.json;
const mcDir = $('Globals').first().json.MINECRAFT_DIR;
if (!fs.existsSync(mcDir)) throw new Error('Minecraft dir not found: ' + mcDir);
const clips = fs.readdirSync(mcDir).filter(f => /\.(mp4|mov|mkv|webm)$/i.test(f));
if (clips.length === 0) throw new Error('No video clips in ' + mcDir);
const pick = clips[Math.floor(Math.random() * clips.length)];
const clipPath = path.join(mcDir, pick);
const startOffset = Math.floor(Math.random() * 25);
const dur = prev.total_audio_duration + 0.5;
return [{ json: { ...prev, mc_clip_path: clipPath, mc_clip_name: pick, mc_start_offset: startOffset, mc_duration: dur } }];

// === Same code as the real B1, copied verbatim ===
const prev = $json;
const g = $('Globals').first().json;
const path = require('path');

const outPath = path.join(g.FINAL_DIR, `${prev.run_id}_final.mp4`);

const ena = wins => wins.map(([s, e]) => `between(t,${s.toFixed(3)},${e.toFixed(3)})`).join('+');
const aEnable = ena(prev.sprite_a_windows) || '0';
const bEnable = ena(prev.sprite_b_windows) || '0';

const dur = prev.mc_duration.toFixed(3);
const musicVol = g.MUSIC_VOLUME || '0.15';

const assEsc = prev.ass_path.replace(/\\/g, '/').replace(/:/g, '\\:');

const filter = [
  `[0:v]trim=start=${prev.mc_start_offset}:duration=${dur},setpts=PTS-STARTPTS,scale=720:1280:force_original_aspect_ratio=increase,crop=720:1280[bg]`,
  `[1:v]scale=480:-1[spA]`,
  `[2:v]scale=480:-1[spB]`,
  `[bg][spA]overlay=x=20:y=H-h-340:enable='${aEnable}'[t1]`,
  `[t1][spB]overlay=x=W-w-20:y=H-h-340:enable='${bEnable}'[t2]`,
  `[t2]subtitles='${assEsc}'[vout]`,
  `[4:a]volume=${musicVol},aloop=loop=-1:size=2e9[music]`,
  `[3:a][music]amix=inputs=2:duration=first:dropout_transition=0[aout]`
].join(';');

const cmd = [
  'ffmpeg -y',
  `-stream_loop -1 -i "${prev.mc_clip_path}"`,
  `-i "${g.SPRITE_A_PATH}"`,
  `-i "${g.SPRITE_B_PATH}"`,
  `-i "${prev.merged_audio_path}"`,
  `-i "${g.MUSIC_BED_PATH}"`,
  `-filter_complex "${filter}"`,
  '-map "[vout]" -map "[aout]"',
  `-t ${dur}`,
  '-c:v libx264 -preset veryfast -crf 21 -pix_fmt yuv420p',
  '-c:a aac -b:a 192k',
  `"${outPath}"`
].join(' ');

return [{ json: { ...prev, final_video_path: outPath, ffmpeg_cmd: cmd } }];

// Verify output and report stats. Does NOT upload anywhere; just leaves the MP4 on disk for inspection.
const fs = require('fs');
const prev = $('Build FFmpeg Command').item.json;

const report = {
  final_video_path: prev.final_video_path,
  exists: fs.existsSync(prev.final_video_path),
  size_bytes: 0,
  size_mb: 0,
  expected_duration_sec: prev.mc_duration,
  ass_path: prev.ass_path,
  audio_path: prev.merged_audio_path,
  minecraft_clip: prev.mc_clip_name,
  sprite_a_windows: prev.sprite_a_windows,
  sprite_b_windows: prev.sprite_b_windows
};

if (report.exists) {
  const stat = fs.statSync(prev.final_video_path);
  report.size_bytes = stat.size;
  report.size_mb = +(stat.size / 1024 / 1024).toFixed(2);
  if (stat.size < 100000) {
    report.warning = 'Output is suspiciously small (<100KB). FFmpeg likely produced a broken file.';
  }
} else {
  report.error = 'FFmpeg did not produce an output file. Check the FFmpeg Assemble Video stderr in the previous node.';
}

return [{ json: report }];
